window._xp=0; window._streak=0; window._cardProgress={};
window._lastStudyDate=0; window._dailyRounds=0; window._todayXP=0;
var mode="vocab", idx=0;
var _importedVocab=[], _importedLogogramme=[], _importedGrammar=[];
var _roundCards=[], _roundIdx=0, _roundCorrect=0;
var CARDS_PER_ROUND=10, DAILY_GOAL=5;

loadProgress();

var _sndOk  = new Audio("data:audio/mpeg;base64,");
var _sndErr = new Audio("data:audio/mpeg;base64,");
function playOk()  { try{ _sndOk.currentTime=0; _sndOk.playbackRate=1.4; _sndOk.play(); }catch(e){} }
function playErr() { try{ _sndErr.currentTime=0; _sndErr.play(); }catch(e){} }

function shuffle(a){return a.slice().sort(function(){return Math.random()-.5;});}

function getVocab()    { return VOCAB.concat(_importedVocab); }
function getLogogramme(){ return LOGOGRAMME.concat(_importedLogogramme); }
function getGrammar()  { return GRAMMAR.concat(_importedGrammar); }

// ── HUD ───────────────────────────────────────────────────────────────────────
function updateHUD(){
  document.getElementById("xp").textContent=window._xp;
  document.getElementById("xp-fill").style.width=Math.min((window._xp%100),100)+"%";
  document.getElementById("streak-count").textContent=window._streak;
  updateStats(); updateRoundBar();
}

function updateStats(){
  var all = mode==="logo" ? getLogogramme() : getVocab();
  var prog=window._cardProgress;
  var learned=Object.keys(prog).filter(function(k){return prog[k].repetitions&&prog[k].repetitions>0;}).length;
  var due=all.filter(function(v){
    var p=prog[v.lemma||v.transliteration]; return !p||isDue(p);
  }).length;
  document.getElementById("stat-total").textContent=all.length+" "+(mode==="logo"?"Logogramme":"Vokabeln");
  document.getElementById("stat-learned").textContent=learned+" gelernt";
  document.getElementById("stat-due").textContent=due+" fällig";
}

function updateRoundBar(){
  document.getElementById("round-num").textContent=_roundIdx;
  document.getElementById("round-fill").style.width=Math.min((_roundIdx/CARDS_PER_ROUND)*100,100)+"%";
  document.getElementById("daily-rounds").textContent=window._dailyRounds;
}

// ── Round ─────────────────────────────────────────────────────────────────────
function buildRound(){
  var all = (mode==="logo") ? getLogogramme() : getVocab();
  var prog=window._cardProgress;
  var due=shuffle(all.filter(function(v){
    var p=prog[v.lemma||v.transliteration]; return p&&p.repetitions>0&&isDue(p);
  }));
  var newC=shuffle(all.filter(function(v){
    var p=prog[v.lemma||v.transliteration]; return !p||p.repetitions===0;
  }));
  _roundCards=due.concat(newC).slice(0,CARDS_PER_ROUND);
  _roundIdx=0; _roundCorrect=0; updateRoundBar();
}

function roundDone(){
  window._dailyRounds++; window._lastStudyDate=today(); saveProgress();
  var area=document.getElementById("exercise-area");
  area.innerHTML=""; document.getElementById("next-btn").style.display="none";
  var box=document.createElement("div"); box.className="round-done";
  var pct=Math.round((_roundCorrect/CARDS_PER_ROUND)*100);
  var dailyDone=window._dailyRounds>=DAILY_GOAL;
  box.innerHTML="<div class='rd-emoji'>"+(dailyDone?"🏆":"🎉")+"</div>"+
    "<div class='rd-title'>"+(dailyDone?"Tagesziel erreicht!":"Runde abgeschlossen!")+"</div>"+
    "<div class='rd-score'>"+_roundCorrect+"/"+CARDS_PER_ROUND+" richtig ("+pct+"%)</div>"+
    "<div class='rd-daily'>Heute: "+window._dailyRounds+" / "+DAILY_GOAL+" Runden</div>"+
    "<button class='rd-btn' id='next-round-btn'>Weiter →</button>";
  area.appendChild(box);
  document.getElementById("next-round-btn").onclick=function(){buildRound();showExercise();};
  playOk(); updateHUD();
}

function done(ok,quality){
  quality=quality!==undefined?quality:(ok?5:1);
  if(ok){window._xp+=10;window._streak++;window._todayXP+=10;}else{window._streak=0;}
  updateHUD(); saveProgress();
  document.getElementById("next-btn").style.display="block";
}

function showDifficultyBtns(area,card,ok){
  var bar=document.createElement("div");bar.className="diff-bar";area.appendChild(bar);
  [{label:"😓 Schwer",q:1,cls:"diff-hard"},{label:"🤔 Mittel",q:3,cls:"diff-mid"},{label:"✓ Gewusst",q:5,cls:"diff-ok"}].forEach(function(b){
    var btn=document.createElement("button");btn.className="diff-btn "+b.cls;btn.textContent=b.label;
    btn.onclick=function(){
      bar.querySelectorAll("button").forEach(function(x){x.disabled=true;x.style.opacity=".4";});
      btn.style.opacity="1";btn.style.fontWeight="700";
      var key=card.lemma||card.transliteration;
      if(key){if(!window._cardProgress[key])window._cardProgress[key]={};sm2(window._cardProgress[key],b.q);}
      if(b.q>=3)_roundCorrect++;
      done(b.q>=3,b.q);
    };
    bar.appendChild(btn);
  });
}

function showExercise(){
  if(_roundIdx>0&&_roundIdx>=_roundCards.length&&(mode==="vocab"||mode==="logo")){roundDone();return;}
  var a=document.getElementById("exercise-area");
  a.innerHTML=""; document.getElementById("next-btn").style.display="none";
  if(mode==="vocab")        renderVocab(a);
  else if(mode==="logo")    renderLogo(a);
  else if(mode==="cloze")   renderCloze(a);
  else if(mode==="order")   renderOrder(a);
  else if(mode==="grammar") renderGrammar(a);
}

document.getElementById("next-btn").onclick=function(){_roundIdx++;showExercise();};
document.querySelectorAll(".module-btn").forEach(function(btn){
  btn.onclick=function(){
    mode=btn.dataset.mode;
    document.querySelectorAll(".module-btn").forEach(function(b){b.classList.toggle("active",b===btn);});
    buildRound(); showExercise();
  };
});

// ── Import ────────────────────────────────────────────────────────────────────
document.getElementById("import-btn").onclick=function(){document.getElementById("file-input").click();};
document.getElementById("file-input").addEventListener("change",function(e){
  var file=e.target.files[0]; if(!file)return;
  var r=new FileReader();
  r.onload=function(ev){
    try{
      var src=ev.target.result;
      var imported=false;
      // Try JSON parse first
      try{
        var obj=JSON.parse(src);
        // Object with GRAMMAR key
        if(obj&&Array.isArray(obj.GRAMMAR)&&obj.GRAMMAR.length){
          _importedGrammar=_importedGrammar.concat(obj.GRAMMAR);
          alert("✓ "+obj.GRAMMAR.length+" Grammatik-Karten importiert.");
          imported=true;
        }
        // Object with VOCAB key
        if(obj&&Array.isArray(obj.VOCAB)&&obj.VOCAB.length){
          _importedVocab=_importedVocab.concat(obj.VOCAB);
          alert("✓ "+obj.VOCAB.length+" Vokabeln importiert.");
          imported=true;
        }
        // Object with LOGOGRAMME key
        if(obj&&Array.isArray(obj.LOGOGRAMME)&&obj.LOGOGRAMME.length){
          _importedLogogramme=_importedLogogramme.concat(obj.LOGOGRAMME);
          alert("✓ "+obj.LOGOGRAMME.length+" Logogramme importiert.");
          imported=true;
        }
        // Plain JSON array → detect by filename and entry structure
        if(!imported&&Array.isArray(obj)&&obj.length){
          var first=obj[0];
          if(first.form&&first.rule){
            _importedGrammar=_importedGrammar.concat(obj);
            alert("✓ "+obj.length+" Grammatik-Karten importiert.");
          } else if(first.cuneiform!==undefined){
            // Use filename to distinguish logogramme vs vocab
            var fname=(file.name||"").toLowerCase();
            if(fname.indexOf("logo")>=0||fname.indexOf("logogramm")>=0){
              _importedLogogramme=_importedLogogramme.concat(obj);
              alert("✓ "+obj.length+" Logogramme importiert.");
            } else {
              _importedVocab=_importedVocab.concat(obj);
              alert("✓ "+obj.length+" Vokabeln importiert.");
            }
          }
          imported=true;
        }
      }catch(je){}
      if(!imported){alert("Keine gültigen Daten gefunden. Bitte JSON-Datei verwenden.");}
      updateHUD();
    }catch(ex){alert("Fehler: "+ex.message);}
    e.target.value="";
  };
  r.readAsText(file);
});

document.getElementById("delete-btn").onclick=function(){
  var n=_importedVocab.length+_importedLogogramme.length+_importedGrammar.length;
  if(!n){alert("Kein Import vorhanden.");return;}
  _importedVocab=[]; _importedLogogramme=[]; _importedGrammar=[];
  alert("✓ Alle importierten Daten gelöscht."); updateHUD();
};

window.onload=function(){updateHUD();buildRound();showExercise();};

// ── Vokabeln ──────────────────────────────────────────────────────────────────
function renderVocab(area){
  var all=getVocab();
  var card=_roundCards.length?_roundCards[_roundIdx%_roundCards.length]:all[idx%all.length];
  var opts=shuffle([card].concat(shuffle(all.filter(function(v){return v!==card;})).slice(0,3)));
  var cu=document.createElement("div");cu.className="vocab-cu";cu.textContent=card.cuneiform;area.appendChild(cu);
  var lemma=document.createElement("div");lemma.className="vocab-lemma";lemma.textContent=card.lemma||card.transliteration;area.appendChild(lemma);
  var tr=document.createElement("div");tr.className="vocab-tr";tr.textContent="["+card.transliteration+"]";area.appendChild(tr);
  var q=document.createElement("div");q.className="vocab-q";q.textContent="Was bedeutet dieses Wort?";area.appendChild(q);
  var grid=document.createElement("div");grid.className="choices";area.appendChild(grid);
  var answered=false;
  opts.forEach(function(opt){
    var btn=document.createElement("button");btn.className="choice-btn";btn.textContent=opt.german;
    btn.onclick=function(){
      if(answered)return;answered=true;
      grid.querySelectorAll("button").forEach(function(b){b.onclick=null;});
      var ok=opt===card;
      btn.classList.add(ok?"correct":"wrong");
      if(!ok)grid.querySelectorAll("button").forEach(function(b){if(b.textContent===card.german)b.classList.add("correct");});
      if(ok)playOk();else playErr();
      showDifficultyBtns(area,card,ok);
    };
    grid.appendChild(btn);
  });
}

// ── Logogramme ────────────────────────────────────────────────────────────────
function renderLogo(area){
  var all=getLogogramme();
  if(!all.length){
    var msg=document.createElement("div");msg.className="vocab-q";
    msg.style.padding="30px 20px";
    msg.innerHTML="<p style='font-size:1.1rem;margin-bottom:12px;'>Noch keine Logogramme geladen.</p>"+
      "<p style='color:var(--muted);font-size:.9rem;'>Bitte über ⬆ Importieren die Datei <b>logogramme_import.json</b> laden.</p>";
    area.appendChild(msg);
    document.getElementById("next-btn").style.display="none";
    return;
  }
  var card=_roundCards.length?_roundCards[_roundIdx%_roundCards.length]:all[idx%all.length];
  var opts=shuffle([card].concat(shuffle(all.filter(function(v){return v!==card;})).slice(0,3)));
  var cu=document.createElement("div");cu.className="vocab-cu";cu.textContent=card.cuneiform||card.transliteration;area.appendChild(cu);
  var lemma=document.createElement("div");lemma.className="vocab-lemma";lemma.textContent=card.lemma||card.transliteration;area.appendChild(lemma);
  var q=document.createElement("div");q.className="vocab-q";q.textContent="Was bedeutet dieses Logogramm?";area.appendChild(q);
  var grid=document.createElement("div");grid.className="choices";area.appendChild(grid);
  var answered=false;
  opts.forEach(function(opt){
    var btn=document.createElement("button");btn.className="choice-btn";btn.textContent=opt.german;
    btn.onclick=function(){
      if(answered)return;answered=true;
      grid.querySelectorAll("button").forEach(function(b){b.onclick=null;});
      var ok=opt===card;
      btn.classList.add(ok?"correct":"wrong");
      if(!ok)grid.querySelectorAll("button").forEach(function(b){if(b.textContent===card.german)b.classList.add("correct");});
      if(ok)playOk();else playErr();
      showDifficultyBtns(area,card,ok);
    };
    grid.appendChild(btn);
  });
}

// ── Grammatik ─────────────────────────────────────────────────────────────────
function renderGrammar(area){
  var gram=getGrammar();
  var card=gram[idx%gram.length];
  var badge=document.createElement("div");badge.className="gram-badge";badge.textContent="Grammatik";area.appendChild(badge);
  var form=document.createElement("div");form.className="gram-form";form.textContent=card.form;area.appendChild(form);
  var ex=document.createElement("p");ex.className="gram-example";
  ex.innerHTML="Paradigma: <em>"+card.example_german+"</em>";area.appendChild(ex);
  var q=document.createElement("p");q.className="vocab-q";q.textContent="Welche grammatische Form ist das?";area.appendChild(q);
  var opts=card.choices?card.choices.slice():shuffle(gram.map(function(c){return c.rule;}).filter(function(r,i,a){return a.indexOf(r)===i&&r!==card.rule;})).slice(0,3).concat([card.rule]);
  var grid=document.createElement("div");grid.className="choices";area.appendChild(grid);
  var answered=false;
  opts.forEach(function(choice){
    var btn=document.createElement("button");btn.className="choice-btn";btn.style.fontSize=".78rem";btn.textContent=choice;
    btn.onclick=function(){
      if(answered)return;answered=true;
      grid.querySelectorAll("button").forEach(function(b){b.onclick=null;});
      var ok=choice===card.rule;
      btn.classList.add(ok?"correct":"wrong");
      if(!ok)grid.querySelectorAll("button").forEach(function(b){if(b.textContent===card.rule)b.classList.add("correct");});
      var fb=document.createElement("div");fb.className="ex-fb "+(ok?"correct":"wrong");
      fb.innerHTML=(ok?"✓ Richtig! ":"✗ Falsch. ")+"<b>"+card.form+"</b> = "+card.rule;
      area.appendChild(fb);
      if(ok)playOk();else playErr();
      idx++;
      showDifficultyBtns(area,card,ok);
    };
    grid.appendChild(btn);
  });
}

// ── Lückentext ────────────────────────────────────────────────────────────────
function renderCloze(area){
  var lesson=LESSONS[idx%LESSONS.length];
  var kws=lesson.key_words;
  var target=kws[Math.floor(Math.random()*kws.length)];
  var gapped=lesson.transliteration.replace(target.token,"___");
  var allKws=LESSONS.reduce(function(a,l){return a.concat(l.key_words);}, []);
  var dists=shuffle(allKws.filter(function(k){return k.token!==target.token;})).slice(0,3).map(function(k){return k.token;});
  var opts=shuffle([target.token].concat(dists));
  var meta=document.createElement("p");meta.className="ex-meta";meta.textContent=lesson.siglum+" · Zeile "+lesson.line;area.appendChild(meta);
  var tr=document.createElement("div");tr.className="ex-tr";tr.innerHTML=gapped.replace("___","<span class='gap'>___</span>");area.appendChild(tr);
  var hint=document.createElement("p");hint.className="ex-hint";hint.textContent="Übersetzung: "+lesson.german;area.appendChild(hint);
  var q=document.createElement("p");q.className="ex-q";q.textContent="Welches Token fehlt?";area.appendChild(q);
  var grid=document.createElement("div");grid.className="ex-choices";area.appendChild(grid);
  var answered=false;
  opts.forEach(function(choice){
    var btn=document.createElement("button");btn.className="choice-btn";btn.textContent=choice;
    btn.onclick=function(){
      if(answered)return;answered=true;
      grid.querySelectorAll("button").forEach(function(b){b.onclick=null;});
      var ok=choice===target.token;
      btn.classList.add(ok?"correct":"wrong");
      if(!ok)grid.querySelectorAll("button").forEach(function(b){if(b.textContent===target.token)b.classList.add("correct");});
      var gap=tr.querySelector(".gap");if(gap){gap.textContent=target.token;gap.className="gap "+(ok?"ok":"err");}
      var fb=document.createElement("div");fb.className="ex-fb "+(ok?"correct":"wrong");
      fb.innerHTML=(ok?"✓ Richtig! ":"✗ Falsch. ")+"<b>"+target.token+"</b> → &#8222;"+target.german+"&#8220;";
      area.appendChild(fb);
      if(ok)playOk();else playErr();
      showDifficultyBtns(area,{},ok);
    };
    grid.appendChild(btn);
  });
}

// ── Reihenfolge ───────────────────────────────────────────────────────────────
function renderOrder(area){
  var lesson=LESSONS[idx%LESSONS.length];
  var kws=lesson.key_words;
  var correct=kws.map(function(k){return k.german;});
  var chips=shuffle(correct.slice());
  var meta=document.createElement("p");meta.className="ex-meta";meta.textContent=lesson.siglum+" · Zeile "+lesson.line;area.appendChild(meta);
  var tr=document.createElement("div");tr.className="ex-tr";tr.textContent=lesson.transliteration;area.appendChild(tr);
  var q=document.createElement("p");q.className="ex-q";q.textContent="Bringe die Bedeutungen in die richtige Reihenfolge:";area.appendChild(q);
  var dz=document.createElement("div");dz.className="order-dz";area.appendChild(dz);
  var slots=[],filled=[];
  correct.forEach(function(_,i){
    var s=document.createElement("div");s.className="order-slot";s.textContent=(i+1)+". ???";
    dz.appendChild(s);slots.push(s);
  });
  var cz=document.createElement("div");cz.className="order-cz";area.appendChild(cz);
  chips.forEach(function(word){
    var chip=document.createElement("button");chip.className="order-chip";chip.textContent=word;
    chip.onclick=function(){
      if(filled.length>=correct.length)return;
      filled.push(word);
      slots[filled.length-1].textContent=(filled.length)+". "+word;
      slots[filled.length-1].classList.add("filled");
      chip.classList.add("used");
      if(filled.length===correct.length){
        var ok=filled.every(function(w,i){return w===correct[i];});
        slots.forEach(function(s,i){s.classList.add(filled[i]===correct[i]?"correct":"wrong");});
        var fb=document.createElement("div");fb.className="ex-fb "+(ok?"correct":"wrong");
        fb.textContent=ok?"✓ Richtige Reihenfolge!":"✗ Falsch. Richtig: "+correct.join(" → ");
        area.appendChild(fb);
        if(ok)playOk();else playErr();
        showDifficultyBtns(area,{},ok);
      }
    };
    cz.appendChild(chip);
  });
}